  // Item Templates
  async findAllItems() {
    return db.select().from(itemTemplates);
  },

  async findItemById(id: string) {
    const rows = await db
      .select()
      .from(itemTemplates)
      .where(eq(itemTemplates.id, id))
      .limit(1);
    return rows[0] ?? null;
  },

  async createItem(input: CreateItemInput) {
    const rows = await db.insert(itemTemplates).values(input).returning();
    return rows[0];
  },

  // Player Inventory
  async getInventory(playerId: string) {
    return db
      .select()
      .from(playerInventory)
      .where(eq(playerInventory.player_id, playerId))
      .orderBy(asc(playerInventory.slot));
  },

  async findSlot(playerId: string, slot: number) {
    const rows = await db
      .select()
      .from(playerInventory)
      .where(
        and(
          eq(playerInventory.player_id, playerId),
          eq(playerInventory.slot, slot),
        ),
      )
      .limit(1);
    return rows[0] ?? null;
  },

  async findItemInInventory(playerId: string, itemId: string) {
    const rows = await db
      .select()
      .from(playerInventory)
      .where(
        and(
          eq(playerInventory.player_id, playerId),
          eq(playerInventory.item_id, itemId),
        ),
      )
      .limit(1);
    return rows[0] ?? null;
  },

  async addItem(
    playerId: string,
    itemId: string,
    quantity: number,
    slot: number,
  ) {
    const rows = await db
      .insert(playerInventory)
      .values({
        player_id: playerId,
        item_id: itemId,
        quantity,
        slot,
      })
      .returning();
    return rows[0];
